class Solution {
    public String largestPalindrome(int n, int k) {
        if (n == 1) {
            for (int i = 9; i >= 0; i--) {
                if (i % k == 0) return String.valueOf(i);
            }
        }
        String max = new String(new char[n]).replace('\0', '9');
        for (int i = Integer.parseInt(max); i > Integer.parseInt(max) / 10; i--) {
            if (i % k != 0) continue;
            String s = String.valueOf(i);
            String rev = new StringBuilder(s).reverse().toString();
            if (s.equals(rev)) return s;
        }
        return "";
    }
}
```
